class Solution:
    def numOfArrays(self, n: int, m: int, k: int) -> int:
        MOD = 10**9 + 7
        # dp[i][j][c] = ways to fill first i elements, current max=j, cost=c
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(i, cur_max, cost):
            if cost > k:
                return 0
            if i == n:
                return 1 if cost == k else 0
            res = 0
            # Append value <= cur_max (no cost change)
            if cur_max > 0:
                res += cur_max * dp(i + 1, cur_max, cost)
            # Append value > cur_max (cost += 1)
            for v in range(cur_max + 1, m + 1):
                res += dp(i + 1, v, cost + 1)
            return res % MOD
        return dp(0, 0, 0)

