var numOfArrays = function(n, m, k) {
    const MOD = 1000000007n;
    // dp[length][maxVal][cost]
    const dp = Array.from({length: n+1}, () =>
        Array.from({length: m+1}, () => new Array(k+1).fill(0n)));
    dp[0][0][0] = 1n;
    for (let length = 0; length < n; length++) {
        for (let cost = 0; cost <= k; cost++) {
            // prefix sum over j
            const prefix = new Array(m + 2).fill(0n);
            for (let j = 0; j <= m; j++) {
                prefix[j+1] = (prefix[j] + dp[length][j][cost]) % MOD;
            }
            for (let j = 1; j <= m; j++) {
                // append value <= j, max stays j
                dp[length+1][j][cost] = (dp[length+1][j][cost] + BigInt(j) * dp[length][j][cost]) % MOD;
                // append value = j, prev max < j
                if (cost + 1 <= k) {
                    dp[length+1][j][cost+1] = (dp[length+1][j][cost+1] + prefix[j]) % MOD;
                }
            }
        }
    }
    let ans = 0n;
    for (let j = 1; j <= m; j++) ans = (ans + dp[n][j][k]) % MOD;
    return Number(ans);
};
